    box-shadow: 0px 2px 4px rgba(0,0,0,0.1), 0px 4px 8px rgba(0,0,0,0.1);
  }
  .navbar-mobile .container .menu a {
    display: inline-block;
    margin: 0 1em;
    line-height: 2.5em;
  }
  .navbar-mobile .container .menu.active {
    display: block;
    white-space: nowrap;
    box-sizing: border-box;
    overflow-x: auto;
  }
  .dark-theme .navbar-mobile .container .menu {
    background: #292a2d;
    border-top: 2px solid #87878d;
  }
  .dark-theme .navbar-mobile .container {
    background: #292a2d !important;
  }
  .archive {
    width: 90%;
  }
  .archive .archive-item .archive-item-date {
    display: none;
  }
  #dynamic-to-top {
    display: none !important;
  }
  .footer {
    height: 3rem;
    width: 100%;
    text-align: center;
    line-height: 1.5rem;
    padding-top: 2em;
  }
  .post-warp {
